ine Learning Basics with sklearn"]},{"ch":"Networking and Security","topics":["Network Architecture","Wireless Technologies","Cybersecurity – Ethical Hacking","SSL/TLS and HTTPS","Security Policies"]},{"ch":"Cloud Computing","topics":["Cloud Service Models – IaaS, PaaS, SaaS","Deployment Models","AWS/Azure Overview","Virtualisation","Serverless Computing"]},{"ch":"Project Work","topics":["Problem Definition","System Design","Implementation","Testing","Documentation","Presentation"]}]}]$$::jsonb)
    AS item(class_num int, subject text, icon text, chapters jsonb)
),
upsert_subjects AS (
  INSERT INTO subjects (name, board, class_num, icon)
  SELECT subject, 'CBSE', class_num, icon
  FROM curriculum
  ON CONFLICT (name, board, class_num) DO UPDATE
  SET icon = EXCLUDED.icon
  RETURNING id, name, class_num
),
chapter_input AS (
  SELECT
    s.id AS subject_id,
    s.name AS subject,
    s.class_num,
    chapter.value->>'ch' AS name,
    chapter.value->'topics' AS topics
  FROM curriculum c
  JOIN subjects s
    ON s.name = c.subject
   AND s.board = 'CBSE'
   AND s.class_num = c.class_num
  CROSS JOIN LATERAL jsonb_array_elements(c.chapters) WITH ORDINALITY AS chapter(value, chapter_order)
),
upsert_chapters AS (
  INSERT INTO chapters (subject_id, name, status)
  SELECT subject_id, name, 'CURRICULUM_READY'
  FROM chapter_input
  ON CONFLICT (subject_id, name) DO UPDATE
  SET status = CASE
    WHEN chapters.status IN ('NO_PDF', 'PDF_READY') THEN 'CURRICULUM_READY'
    ELSE chapters.status
  END
  RETURNING id, subject_id, name
),
chapter_refs AS (
  SELECT ch.id AS chapter_id, ci.topics
  FROM chapter_input ci
  JOIN upsert_chapters ch
    ON ch.subject_id = ci.subject_id
   AND ch.name = ci.name
),
topic_input AS (
  SELECT
    chapter_id,
    topic.value AS name,
    CASE WHEN topic.topic_order = 1 THEN 'HIGH' ELSE 'MEDIUM' END AS importance
  FROM chapter_refs
  CROSS JOIN LATERAL jsonb_array_elements_text(chapter_refs.topics) WITH ORDINALITY AS topic(value, topic_order)
)
INSERT INTO topics (chapter_id, name, importance)
SELECT chapter_id, name, importance
FROM topic_input
ON CONFLICT (chapter_id, name) DO UPDATE
SET importance = EXCLUDED.importance;

DELETE FROM chapters c
WHERE c.status = 'NO_PDF'
AND c.pdf_url IS NULL
AND NOT EXISTS (SELECT 1 FROM topics t WHERE t.chapter_id = c.id)
AND NOT EXISTS (SELECT 1 FROM questions q WHERE q.chapter_id = c.id)
AND NOT EXISTS (
  SELECT 1
  FROM paper_questions pq
  JOIN questions q ON q.id = pq.question_id
  WHERE q.chapter_id = c.id
);
